const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401 } };
if (!body.message) return { json: { _empty: true, status: 400, error: 'message required' } };
return { json: { token, topic_id: body.topic_id || null, session_id: body.session_id || null, message: body.message } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401 } };
const i = $('Extract').first().json;
return { json: { _ok: true, user_id: row.user_id, topic_id: i.topic_id, session_id: i.session_id, message: i.message } };

const allOf = function (name) { try { const items = $(name).all().map(function (i) { return i.json; }); if (items.length === 1 && Array.isArray(items[0])) return items[0]; return items; } catch (e) { return []; } };
const ctx = $('Check Session').first().json;
const sessionRows = allOf('Fetch Session');
const topicRows   = allOf('Fetch Topic');
const session = sessionRows[0] || null;
const topic   = topicRows[0]   || null;
const history = (session && Array.isArray(session.session_messages)) ? session.session_messages : [];
history.push({ role: 'user', content: ctx.message, timestamp: new Date().toISOString() });
const topicCtx = topic ? ('Topic: ' + topic.topic_title + '\nCategory: ' + topic.topic_category + '\nDifficulty: ' + (topic.difficulty_level || 'beginner') + '\nLearning objectives: ' + ((topic.learning_objectives || []).join('; '))) : 'General sales coaching.';
const systemPrompt = 'You are the Crystallux Training Coach. Style: warm, Socratic, action-oriented. Push the learner with questions before giving answers.\n\n' + topicCtx + '\n\nOutput ONE concise coach reply (2-5 sentences). Wrap actionable practice cues in **bold**. If the learner has demonstrated competency on this topic, end with a competency score line in the form [SCORE: 0-100].';
const messages = history.slice(-10).map(function (m) { return { role: m.role === 'coach' ? 'assistant' : 'user', content: m.content }; });
return { json: { session, topic, history, claude_payload: { model: 'claude-sonnet-4-5-20250929', max_tokens: 600, temperature: 0.5, system: systemPrompt, messages: messages } } };

const ctxAll = $('Build Prompt').first().json;
const session = ctxAll.session;
const history = ctxAll.history || [];
const resp = $input.item.json || {};
let reply = '';
try { reply = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
if (!reply) reply = 'Tell me a little more about the situation you\'re working through.';
const scoreMatch = /\[SCORE:\s*(\d{1,3})\]/.exec(reply);
const competencyScore = scoreMatch ? Math.min(100, parseInt(scoreMatch[1])) : null;
history.push({ role: 'coach', content: reply.replace(/\[SCORE:[^\]]+\]/, '').trim(), timestamp: new Date().toISOString() });
const ctx = $('Check Session').first().json;
const row = session ? { update_id: session.id, session_messages: history, last_activity_at: new Date().toISOString(), competency_score: competencyScore } : { user_id: ctx.user_id, topic_id: ctx.topic_id, session_messages: history, last_activity_at: new Date().toISOString(), competency_score: competencyScore };
return { json: { row, reply: history[history.length - 1].content, competency_score: competencyScore, is_update: !!session } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : rows;
const replyData = $('Build Update').first().json;
return { json: { ok: true, session_id: row ? row.id : null, reply: replyData.reply, competency_score: replyData.competency_score } };
